package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetName() throws Exception {
    String expectedName = "TestItem";

    // Use reflection to create instance since constructor is not fully shown as public in snippet
    var constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    LineItem lineItem = constructor.newInstance(expectedName, 5, 1000L, "USD");

    String actualName = lineItem.getName();

    assertEquals(expectedName, actualName);
  }
}
